// Catch HelpScout webhook and route based on X-HelpScout-Event header
const headers = $input.first().json.headers;
const body = $input.first().json.body;
const eventType = headers['x-helpscout-event'];

// Only process new conversations or customer replies
if (eventType === 'convo.created' || eventType === 'convo.customer.reply.created') {
  return [{ json: { eventType, payload: body } }];
}

// Ignore other events to save API calls
return [];

// Extract core identifiers from HelpScout v2 payload
const payload = $json.payload;
const email = payload.primaryCustomer?.emails?.[0]?.value || payload.customer?.email;
const ticketId = payload.id;
const subject = payload.subject;
const preview = payload.preview;

if (!email) return []; // Drop if no email

return [{ json: { email, ticketId, subject, preview, source: 'helpscout' } }];

const hsData = $json[0]?.results?.[0] || {};
const smsData = $json[1]?.messages || [];
const inputData = $json[0]?.inputData || {};

let smsHistoryString = "No recent SMS.";
if (smsData.length > 0) {
  smsHistoryString = smsData.map(m => `[${m.direction}] ${m.body}`).join(' | ');
}

const sharedContext = `
--- CUSTOMER 360 CONTEXT ---
1. CURRENT TICKET (Help Scout): ID {{ $json["ticketId"] }}, Subject: {{ $json["subject"] }}, Preview: {{ $json["preview"] }}
2. HUBSPOT CRM: Deal Stage: ${hsData.dealstage || 'N/A'}, Account Tier: ${hsData.account_tier || 'Free'}, Onboarding Status: ${hsData.onboarding_status || 'N/A'}, Associated Deal Value: ${hsData.associated_deal_amount || 0}
3. RECENT SMS ACTIVITY: ${smsHistoryString}
---------------------------
`;

return [{ json: { 
  sharedContext, 
  email: inputData.email, 
  ticketId: inputData.ticketId,
  accountTier: hsData.account_tier || 'Free',
  dealValue: Number(hsData.associated_deal_amount) || 0
}}];

